cimport cython

DEF MAX_ADAPTER = 256

@cython.boundscheck(False)  # Deactivate bounds checking
@cython.wraparound(False)   # Deactivate negative indexing
@cython.cdivision(True)     # Deactivate zero division check
cpdef int run(s):
    cdef bint adapters[MAX_ADAPTER]

    cdef int i
    for i in range(MAX_ADAPTER):
        adapters[i] = 0

    cdef int max_adapters = 0
    cdef int adapter
    cdef str line
    for line in s.strip().splitlines():
        adapter = int(line)
        adapters[adapter] = 1
        if adapter > max_adapters:
            max_adapters = adapter

    cdef int counts[5]
    for i in range(5):
        counts[i] = 0

    cdef int diff = 0
    for i in range(1, max_adapters + 1):
        diff += 1
        if adapters[i]:
            counts[diff] += 1
            diff = 0
    counts[3] += 1
    return counts[1] * counts[3]

from libc.stdlib cimport malloc

cdef int seq_len = 17
cdef char *seq_dest = <char *>malloc(seq_len + 1)
seq_dest[seq_len] = '\0'

def reverse_complement_c_v1(str seq):
    cdef bytes py_bytes = seq.encode('ascii')
    cdef char *seq_src = py_bytes
    cdef int i = 0
    cdef int d = 0
    for i in range(seq_len):
        d = seq_len - i - 1
        if seq_src[i] == 'A':
            seq_dest[d] = 'T'
        elif seq_src[i] == 'G':
            seq_dest[d] = 'C'
        elif seq_src[i] == 'C':
            seq_dest[d] = 'G'
        elif seq_src[i] == 'T':
            seq_dest[d] = 'A'
    return seq_dest[:seq_len].decode('ascii')
